SELECT task_log_no AS taskLogNo, task_code AS taskCode, task_name AS taskName, run_mode AS runMode, task_status AS taskStatus, task_status_type AS taskStatusType, severity_level AS severityLevel, severity_level_type AS severityLevelType, escalation_status AS escalationStatus, escalation_status_type AS escalationStatusType, processed_count AS processedCount, success_count AS successCount, fail_count AS failCount, summary_comment AS summaryComment, suggested_action AS suggestedAction, recommended_route AS recommendedRoute, triggered_by AS triggeredBy, DATE_FORMAT(started_at, '%Y-%m-%d %H:%i:%s') AS startedAt, DATE_FORMAT(completed_at, '%Y-%m-%d %H:%i:%s') AS completedAt FROM t_payment_task_run_log
AND task_code = #{taskCode}
AND run_mode = #{runMode}
AND task_status = #{taskStatus}
AND severity_level = #{severityLevel}
ORDER BY started_at DESC, id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM t_payment_task_run_log


        AND task_code = #{taskCode}


        AND run_mode = #{runMode}


        AND task_status = #{taskStatus}


        AND severity_level = #{severityLevel}
